/**
 * 高频人类行为轨迹生成器
 * @param {number} targetX - 目标滑动距离 (例如 145)
 * @param {number} expectedCount - 期望生成的数组长度 (默认 150 左右)
 */
function generateDenseTrace(targetX, expectedCount = 150) {
  const trace = [];
  let curX = 4; // 起始 dragX 始终从 4 开始
  let curY = 0; // 初始 Y
  let curTime = 125; // 初始时间戳

  // 辅助函数：推入一个点
  const add = (x, y, t) => trace.push([Math.round(x), Math.round(y), t, 1]);

  // 1. 起始点的粘滞感 (前 10-20 条数据，X 增加极慢)
  for (let i = 0; i < 15; i++) {
    curX += Math.random() > 0.7 ? 1 : 0;
    curTime += Math.floor(Math.random() * 3) + 2;
    add(curX, curY, curTime);
  }

  // 2. 加速与匀速阶段 (占据 70% 的数据量)
  const midCount = Math.floor(expectedCount * 0.7);
  for (let i = 0; i < midCount; i++) {
    // X 轴：根据剩余距离动态调整步长
    let remain = targetX - curX;
    let stepX = remain > 20 ? Math.random() * 2 + 1 : Math.random() * 1;
    curX += stepX;

    // Y 轴：模拟你示例中那种逐渐下掉的趋势 (0 -> -26)
    // 只有在 X 移动到一定程度后，Y 才开始偏移
    if (curX > 30 && Math.random() > 0.6) {
      curY -= Math.random() * 0.8;
    }

    // 时间：极其密集，大部分在 1-3ms 之间
    curTime += Math.floor(Math.random() * 3) + 1;

    // 模拟采样重复 (即坐标没变但记录了一次)
    if (Math.random() > 0.8) {
      add(curX, curY, curTime);
      curTime += 1;
    }

    add(curX, curY, curTime);

    if (curX >= targetX - 2) break; // 接近终点时进入微调
  }

  // 3. 终点微调与长尾 (模拟你示例最后几百毫秒的停顿)
  while (curX < targetX) {
    curX += 0.5;
    curTime += Math.floor(Math.random() * 5) + 2;
    add(targetX, curY, curTime);
  }

  // 4. 关键：补充最后几条大数据量的时间跳跃 (模拟用户滑到位后松手前的延迟)
  let lastTime = trace[trace.length - 1][2];
  const finalDelays = [200, 450, 10]; // 模拟你数据末尾那种 700ms -> 1000ms 的跳跃
  finalDelays.forEach((d) => {
    lastTime += d;
    add(targetX, curY, lastTime);
  });

  return trace;
}

